action.old_str:
llvm::Value*
EmitIR::operator()(DeclRefExpr* obj)
{
  auto ptr = llvm::cast<llvm::Value>(obj->decl->any);
  if (auto global = llvm::dyn_cast<llvm::GlobalValue>(ptr)) {
    return mCurIrb->CreateLoad(global->getValueType(), global);
  }
  if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(ptr)) {
    return mCurIrb->CreateLoad(alloca->getAllocatedType(), alloca);
  }
  ABORT();
}

